import anthropic, json
from datetime import datetime

client = anthropic.Anthropic()

SIGN_OFF_RECORD_TOOL = {
    "name": "create_sign_off_record",
    "description": "Create a formal design sign-off record for a Claude feature",
    "input_schema": {
        "type": "object",
        "required": ["feature_id", "feature_name", "decisions", "overall_status",
                     "sign_off_date", "conditions"],
        "properties": {
            "feature_id": {"type": "string"},
            "feature_name": {"type": "string"},
            "decisions": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["decision", "accountable", "responsible",
                                 "status", "criteria_met", "notes"],
                    "properties": {
                        "decision": {"type": "string"},
                        "accountable": {"type": "string"},
                        "responsible": {"type": "array", "items": {"type": "string"}},
                        "status": {"enum": ["APPROVED", "APPROVED_WITH_CONDITIONS", "REJECTED"]},
                        "criteria_met": {"type": "array", "items": {"type": "string"}},
                        "criteria_not_met": {"type": "array", "items": {"type": "string"}},
                        "notes": {"type": "string"}
                    }
                }
            },
            "overall_status": {"enum": ["APPROVED", "APPROVED_WITH_CONDITIONS", "REJECTED"]},
            "sign_off_date": {"type": "string"},
            "conditions": {
                "type": "array",
                "description": "Conditions that must be met before build begins (for APPROVED_WITH_CONDITIONS)",
                "items": {
                    "type": "object",
                    "properties": {
                        "condition": {"type": "string"},
                        "owner": {"type": "string"},
                        "due_date": {"type": "string"}
                    }
                }
            }
        }
    }
}

def create_sign_off_record(feature_id, feature_name, review_inputs):
    """
    review_inputs: dict with keys:
      behaviour_spec_audit, eval_plan_audit, risk_ethics_audit,
      prompt_audit, prototype_audit, ops_audit
    Each audit is the output of the corresponding audit function.
    """
    today = datetime.today().strftime("%Y-%m-%d")
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=4096,
        tools=[SIGN_OFF_RECORD_TOOL],
        tool_choice={"type": "tool", "name": "create_sign_off_record"},
        messages=[{
            "role": "user",
            "content": (
                f"Create a sign-off record for feature {feature_id}: {feature_name}.\n\n"
                f"Review results:\n{json.dumps(review_inputs, indent=2)}\n\n"
                f"Today is {today}.\n\n"
                "Rules:\n"
                "- overall_status=APPROVED only if all six decisions APPROVED\n"
                "- overall_status=APPROVED_WITH_CONDITIONS if any YELLOW dimension\n"
                "- overall_status=REJECTED if any RED dimension\n"
                "- Each condition in the conditions list must have an owner and due_date\n"
                "- sign_off_date is today only if overall_status=APPROVED"
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

ESCALATION_TOOL = {
    "name": "generate_escalation_plan",
    "description": "Generate an escalation plan for a blocked sign-off",
    "input_schema": {
        "type": "object",
        "required": ["blocking_dimension", "blocking_issues", "steps",
                     "owner", "sla_days", "unblock_criteria"],
        "properties": {
            "blocking_dimension": {"type": "string"},
            "blocking_issues": {"type": "array", "items": {"type": "string"}},
            "steps": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["step", "owner", "action", "expected_output"],
                    "properties": {
                        "step": {"type": "integer"},
                        "owner": {"type": "string"},
                        "action": {"type": "string"},
                        "expected_output": {"type": "string"}
                    }
                }
            },
            "owner": {"type": "string"},
            "sla_days": {"type": "integer"},
            "unblock_criteria": {"type": "array", "items": {"type": "string"}}
        }
    }
}

def generate_escalation_plan(blocking_dimension, blocking_issues, team_context):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[ESCALATION_TOOL],
        tool_choice={"type": "tool", "name": "generate_escalation_plan"},
        messages=[{
            "role": "user",
            "content": (
                f"Generate an escalation plan for a sign-off blocked on dimension: {blocking_dimension}\n\n"
                f"Blocking issues:\n{json.dumps(blocking_issues)}\n\n"
                f"Team context:\n{json.dumps(team_context)}\n\n"
                "Generate concrete, actionable steps with named owners drawn from team_context. "
                "SLA should be realistic given the type of issue. "
                "Unblock criteria should be specific and verifiable."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

